                    alignItems: "center",
                    gap: 4,
                  }}
                >
                  <div
                    style={{
                      width: 6,
                      height: 6,
                      borderRadius: "50%",
                      background: "var(--color-accent-amber)",
                    }}
                  />{" "}
                  Upcoming
                </span>
                <span
                  style={{
                    fontSize: 10,
                    display: "flex",
                    alignItems: "center",
                    gap: 4,
                  }}
                >
                  <div
                    style={{
                      width: 6,
                      height: 6,
                      borderRadius: "50%",
                      background: "var(--color-accent-rose)",
                    }}
                  />{" "}
                  Overdue
                </span>
              </div>
            </div>

            {/* Custom Dynamic Calendar */}
            <EMICalendar
              events={calendarData}
              onDateClick={(d) => setSelectedEmiDate(d)}
            />
          </div>

          {/* Upcoming EMIs removed and moved to Popover in header */}
        </div>
      </div>

      {/* Bottom Bar */}

      {/* Context Menu */}
      {contextMenu && (
        <div
          style={{
            position: "fixed",
            top: contextMenu.y,
            left: contextMenu.x,
            background: "var(--color-bg-secondary)",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--radius-md)",
            boxShadow: "0 4px 12px rgba(0,0,0,0.5)",
            padding: 4,
            zIndex: 1000,
            display: "flex",
            flexDirection: "column",
            minWidth: 120,
          }}
          onClick={(e) => e.stopPropagation()}
        >
          <button
            onClick={() => {
              setShowEditModal(contextMenu.debt);
              setContextMenu(null);
            }}
            style={{
              padding: "8px 12px",
              textAlign: "left",
              background: "transparent",
              border: "none",
              color: "var(--color-text-primary)",
              fontSize: 13,
              cursor: "pointer",
              borderRadius: 4,
            }}
            onMouseEnter={(e) =>
              (e.currentTarget.style.background = "var(--color-border)")
            }
            onMouseLeave={(e) =>
              (e.currentTarget.style.background = "transparent")
            }
          >
            Edit
          </button>
          <button
            onClick={() => {
              setShowDeleteModal(contextMenu.debt);
              setContextMenu(null);
            }}
            style={{
              padding: "8px 12px",
              textAlign: "left",
              background: "transparent",
              border: "none",
              color: "var(--color-accent-rose)",
              fontSize: 13,
              cursor: "pointer",
              borderRadius: 4,
            }}
            onMouseEnter={(e) =>
              (e.currentTarget.style.background = "var(--color-bg-tertiary)")
            }
            onMouseLeave={(e) =>
              (e.currentTarget.style.background = "transparent")
            }
          >
            Delete
          </button>
        </div>
      )}

      {/* Modals */}
      {showAddModal && (
        <AddDebtModal
          onClose={() => setShowAddModal(false)}
          onRefresh={fetchData}
        />
      )}
      {showEditModal && (
        <AddDebtModal
          initialData={showEditModal}
          onClose={() => setShowEditModal(null)}
          onRefresh={fetchData}
        />
      )}
      {showDeleteModal && (
        <DeleteDebtModal
